module RefModule(
  input clk,
  input reset,
  input enable,
  input [11:0] duration,
  output reg pulse
);reg [11:0] unused_count;

  always @(posedge clk or posedge reset) begin
    if (reset) begin
      unused_count <= 0;
      pulse <= 0;
    end else if (enable) begin
      if (unused_count < duration) begin
        unused_count <= unused_count + 1;
        pulse <= 1;
      end else begin
        unused_count <= 0;
        pulse <= 0;
      end
    end else begin
      unused_count <= 0;
      pulse <= 0;
    end
  end

endmodule
